function LGameLogin:CheckLoginDataValid()
	if not self._loginSdkAccount then return false end

	local sdkSign = gLSdkImpl:CallMethod(LSdkMethod.GetSdkSign) or ""
	local sdkTimeStamp = gLSdkImpl:CallMethod(LSdkMethod.GetSdkTimeStamp) or ""
	if self._loginSdkAccount ~= self:GetSdkAccount() or
			self._loginSdkTimestamp ~= sdkTimeStamp or
			self._loginSdkSign ~= sdkSign then
		LogError("checkLoginDataValid ")
		return false
	end
	return true
end

function LGameLogin:CheckLoginBack()
	if self._gameStep > LStepLoginConst.STEP_NONE then
		self:Step_BackLogin()
		return false
	end
	return true
end

