function LGameLogin:OnApplicationPause(isPause)
	if (isPause) then
		self._backGroundTime = os.time()
	else
		----挂后台超过一定时间，检测是否需要热更新
		local osTime = os.time()
		local backGroundTime = self._backGroundTime or osTime
		local backPassTime = osTime - backGroundTime
		-- 挂在后台20分钟
		if backPassTime > 1200 then
			self:Step_QueryServerListFromWeb(function(resultTbl)
				-- 服务器状态
				local curServerId = self:GetServerId()
				if curServerId then
					local serveData = resultTbl.server
					if not serveData then return end
					local bServerEnable = false
					if serveData then
						bServerEnable = (serveData.state == 1)
					end
					
					if not bServerEnable then
						local pb = {type = 1}
						self:OnQuitResp(pb)
					end
				end
			end, self:GetServerId())
		end
	end
end

