function LGameLogin:IsServerValidShow(serverInfo, isNotCheckExclusive)
    local controlInfo = self._serverControlInfo
    if controlInfo then
        if controlInfo == -1 then
            return false
        end
        if controlInfo > 0 and serverInfo.id > controlInfo then
            return false
        end
    end
    if 1 ~= self:IsWhiteUser() and serverInfo.state == 3 then
        return false
    end

    if not isNotCheckExclusive and self._exclusiveDataMap then
        --非独占模式不显示独占字段的服
        if not self._isExclusiveMode then
            if not string.isempty(self._exclusiveDataMap[tostring(serverInfo.id)]) then
                return false
            end
        else
            local resVer = gLxServerList.activePackageVersion
            if self._exclusiveDataMap[tostring(serverInfo.id)] ~= resVer then
                return false
            end
        end
    end

    return true
end


--独占服务器检测
function LGameLogin:CheckExclusiveServer(resultTbl)
    local resVer = gLxServerList.activePackageVersion
    ----local resVerCheck = tostring(resVer)..'_'..LNativeHelper.GetVersionName()
    local resVerCheck = tostring(resVer)
    local exclusiveList = {}
    local exclusiveMap = resultTbl.exclusive or {}
    local exclusiveData = {}
    for k, v in pairs(exclusiveMap) do
        exclusiveData[tostring(v.id)] = v.exclusive
        if v.exclusive == resVerCheck and self:IsServerValidShow(v, true) then
            table.insert(exclusiveList, v)
        end
    end
    self._exclusiveDataMap = exclusiveData

    self._isExclusiveMode = #exclusiveList > 0

    if not self._isExclusiveMode then
        return
    end

    local defaultServerList = {}
    local groupList = {}
    local groupServerList = {}
    local serverKeyList = {}

    self._defaultServerList = defaultServerList
    self._groupList = groupList
    self._groupServerList = groupServerList
    self._serverKeyList = serverKeyList

    table.sort(exclusiveList, function(sA, sB)
        return sA.orders > sB.orders
    end)
    self._exclusiveList = exclusiveList

    for k, v in ipairs(exclusiveList) do
        serverKeyList[v.id] = v
        local gsGroupId = v.gsGroupId

        local gsList = groupServerList[gsGroupId]
        if not gsList then
            gsList = {}
            groupServerList[gsGroupId] = gsList
            local groupData = {
                gsGroupName = v.gsGroupName,
                gsGroupDesc = v.gsGroupDesc,
                gsGroupId = gsGroupId,
                serverList = gsList
            }
            table.insert(groupList, groupData)
        end
        table.insert(gsList, v)
    end
end

function LGameLogin:InitServerList(resultTbl, isFromLogin)
    if (not resultTbl) then
        LogError("decode server json data error ... ")
        return nil
    end
    self._gameServerData = resultTbl

    local servicesUrl = resultTbl.servicesUrl or ""
    if '/' ~= string.sub(servicesUrl, string.len(servicesUrl)) then
        servicesUrl = servicesUrl .. '/'
    end
    self._servicesUrl = servicesUrl

    local servicesUrl2 = resultTbl.servicesUrl2 or ""
    if '/' ~= string.sub(servicesUrl2, string.len(servicesUrl2)) then
        servicesUrl2 = servicesUrl2 .. '/'
    end
    self._servicesUrl2 = servicesUrl2

    self._servicesUrList = {}
    table.insert(self._servicesUrList, servicesUrl)

    if not string.isempty(servicesUrl2) and servicesUrl2 ~= servicesUrl then
        table.insert(self._servicesUrList, servicesUrl2)
    end

    self._isWhiteUser = resultTbl.iswl or 0
    local isWhite = self._isWhiteUser == 1

    --不显示的服务器信息
    local abnormalChannels = resultTbl.abnormalChannels or {}
    local dicAbnormalChannel = {}
    for k, v in ipairs(abnormalChannels) do
        dicAbnormalChannel[v.packageId] = v.controlInfo
    end
    self._abnormalChannelMap = dicAbnormalChannel
    local packageId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or 0
    local controlInfo = dicAbnormalChannel[tostring(packageId)]
    self._serverControlInfo = tonumber(controlInfo)

    --服务器分组信息
    local gsGroup = {}
    local bAdd = false
    for k, v in ipairs(resultTbl.gsGroup or {}) do
        local gsCount = v.gsCount
        bAdd = true
        if gsCount and gsCount <= 0 then
            bAdd = isWhite
        end
        if bAdd then
            v.gsGroupDesc = tonumber(v.gsGroupDesc) or 0
            table.insert(gsGroup, v)
        end
    end

    table.sort(gsGroup, function(gA, gB)
        return gA.gsGroupDesc > gB.gsGroupDesc
    end)
    self._groupList = gsGroup

    local serverKeyList = {}
    self._serverKeyList = serverKeyList

    self._exclusiveDataMap = {}

    self:CheckExclusiveServer(resultTbl)

    if not self._isExclusiveMode then
        --推荐服务器列表
        local defaultServerList = {}
        local setDefaultList = resultTbl.setDefault or {}
        for k, v in pairs(setDefaultList) do
            if self:IsServerValidShow(v) then
                table.insert(defaultServerList, v)
                serverKeyList[v.id] = v
            end
        end
        table.sort(defaultServerList, function(sA, sB)
            return sA.orders < sB.orders
        end)
        self._defaultServerList = defaultServerList

        local groupServerList = {}
        self._groupServerList = groupServerList
    end

    --过滤过期 无效的公告
    local nowTime = os.time()
    local notices = {}
    for k, v in ipairs(resultTbl.platformNotices or {}) do
        local noticeEndTime = tonumber(v.endTime) / 1000
        local noticeBeginTime = tonumber(v.beginTime) / 1000
        if noticeEndTime > nowTime and noticeBeginTime <= nowTime then
            table.insert(notices, v)
        end
    end
    self._platformNotices = notices

    self._channelInfo = resultTbl.channelInfo

    self._openRealName = resultTbl["openRealName"]
    self._openPhoneBinding = resultTbl["openPhoneBinding"]
    self._activityWebUrl = resultTbl["gameActivityHttpUrl"]
    self._iosRatingUrl = resultTbl["gameRatingIosUrl"]
    self._androidRatingUrl = resultTbl["gameRatingAndroidUrl"]
    self._openGameRating = resultTbl["openGameRating"]
    self._openTourist = resultTbl["openTourist"]
    self._copyUuid = resultTbl["copyUuid"]
    self._isOpenFacebook = resultTbl["toFacebook"]
    self._openBindAccount = resultTbl["bindAccount"]
    self._questionUrl = resultTbl["questionnaireHttpUrl"]
    self._videoResPath = resultTbl["videoResourcesPath"]
    self._isOpenSex = toboolean(resultTbl["isOpenSex"])
    self._sexLvl = checknumber(resultTbl["sexLvl"])
    self._isOpenHarmonious = checknumber(resultTbl["isOpenHarmonious"]) == 1
    self._gateways = resultTbl["gateway"]

    local serverStateJsonUrl = resultTbl.serverStateJsonUrl
    if not string.isempty(serverStateJsonUrl) then
        if not PRODUCT_G_VER or PRODUCT_G_VER == 0 then
            local urlList = { serverStateJsonUrl }
            LxHttpHelper.DoWebRequestURL(false, urlList, "", function(...)
                if not self._isDestroy then
                    self:OnServerStateList(...)
                end
            end)
        end
    end

    self:QueryMaskDataFromWeb()

    if isFromLogin then
        FireEvent(EventNames.LOGIN_SERVERLIST_OK)
        gLxServerList:InitUpdateConfig(resultTbl.updateConfig)
    end
end

function LGameLogin:OnServerStateList(ret, result, url)
    if (ret ~= CS.YXWebRet.ok) then
        LogError("url=" .. url)
        LogError(tostring(ret) .. " | " .. tostring(result))
        return nil
    end

    LXFW.LxLog.WEB(result)
    self._serverStateList = {}
    local resultTbl = JSON.decode(result)
    for k, v in pairs(resultTbl) do
        k, v = tonumber(k), tonumber(v)
        self._serverStateList[k] = v
    end
    FireEvent(EventNames.LOGIN_SERVERLISTSTATE_OK)
end

function LGameLogin:GetServerStateById(id)
    if self._serverStateList then
        if self._serverStateList[id] then
            return self._serverStateList[id]
        end
        --printInfoN("====== 没有去到对应服务器的状态，默认1")
        return 1
    end
    --printInfoN("====== 暂未获取到所有服务器对应状态")
    return 1
end

