---查询屏蔽词
function LGameLogin:QueryMaskDataFromWeb()
    local configTable = self:GetMaskDataCfgTable()
    if not configTable then
        return
    end

    local maskVer = configTable.maskVer or ""
    local localMaskVer = LPlayerPrefs.maskVer or ""

    if string.isempty(maskVer) then
        return
    end

    if maskVer == localMaskVer then
        local path = self:GetMaskDataFilePath()
        local str = LFileHelper.ReadAllTextFromCache(path)
        local resultTbl
        if not string.isempty(str) then
            local base64Str = CS.Base64Decode(str)
            resultTbl = string.split(base64Str, "\n")
        end
        if (resultTbl) then
            self._maskWebData = resultTbl
            return
        end
    end
    local maskUrl = configTable.maskUrl or ""
    if string.isempty(maskUrl) then
        return
    end
    LServerUtil.DownFileMaskDataFromWeb(maskUrl, maskVer, function(...)
        self:OnMaskDataFromWenResult(maskVer, ...)
    end)
end

function LGameLogin:GetMaskDataFilePath()
    local path = CS.AppPersistentDataPath() .. "local_mask.json"
    return path
end

function LGameLogin:GetMaskDataCfgTable()
    if not self._gameServerData then
        return
    end
    local updateConfig = self._gameServerData.updateConfig
    if not updateConfig then
        return
    end
    local resKey = "default"
    local configTable = nil
    for k, v in ipairs(updateConfig) do
        if v.updateKey == resKey then
            configTable = v
            break
        end
    end
    return configTable
end

function LGameLogin:OnMaskDataFromWenResult(maskVer, ret, result, url, bytes)
    if self._isDestroy then
        return
    end
    if ret ~= CS.YXWebRet.ok then
        return
    end
    if (not bytes) then
        return
    end

    local configTable = self:GetMaskDataCfgTable()
    if not configTable then
        return
    end

    local nowMaskVer = configTable.maskVer or ""
    if nowMaskVer ~= maskVer then
        return
    end
    --local bOk, str = CS.DecodeCryptKeyword(bytes, "r18", true, false)
    --if not bOk then return end
    local Utf8Encoding = System.Text.UTF8Encoding.New(false)
    local str = Utf8Encoding:GetString(bytes)
    local path = self:GetMaskDataFilePath()

    LFileHelper.WriteAllTextToCache(path, str)

    LPlayerPrefs.SetMaskVer(maskVer)

    local resultTbl
    if not string.isempty(str) then
        local base64Str = CS.Base64Decode(str)
        resultTbl = string.split(base64Str, "\n")
    end

    if (resultTbl) then
        self._maskWebData = resultTbl
        LWordMaskUtil.AddTrie(resultTbl)
    end
end

function LGameLogin:GetMaskWebData()
    return self._maskWebData
end

