--- 查询服务器玩家的角色
------------------------------------------------------------------
function LGameLogin:Step_QueryUserPlayerInfoFromWeb()
    self._isPlayerInfoReqing = true
    local urlList = self._servicesUrList or {""}
    local platformId = self:GetPlatformId() or 0

    local packageId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or 0

    if tonumber(packageId) == 0 then
        packageId = LGameSettings.platformId or packageId
    end

    local sdkUserId = self:GetSdkAccount() or ""
    local oldUserId = sdkUserId
    local mathStr = string.match(sdkUserId, _USER_ID_PATTERN)
    if mathStr then
        sdkUserId = mathStr
    end
    local urlSuffix = "api/playerSimplyInfo.do?platformId=" .. platformId .. "&userId=" .. tostring(sdkUserId) .. "&packId=" .. tostring(packageId)
    urlSuffix = LUtil.MakeB64SendData(urlSuffix)
    LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function(...)
        if not self._isDestroy and oldUserId == self:GetSdkAccount() then
            self:OnPlayerInfoList(...)
            FireEvent(EventNames.LOGIN_SERVERLIST_PLAY_OK)
        end
    end)
end

function LGameLogin:OnPlayerInfoList(ret, result, url)
    if (ret ~= CS.YXWebRet.ok) then
        LogError(tostring(ret) .. " | " .. tostring(result))
        return nil
    end
    LXFW.LxLog.WEB(result)
    local resultTbl = JSON.decode(result)
    if (not resultTbl) then
        LogError("decode server json data error ... ")
        return nil
    end

    local playerInfoList = {}
    self._playerInfoList = playerInfoList
    self._isPlayerInfoReqing = false
    local myServerList = nil

    for i, v in pairs(resultTbl or {}) do
        local fid = tonumber(v.fid)
        if i == "details" and not fid then
            myServerList = v
        else
            if fid then
                playerInfoList[fid] = {
                    userId = i,
                    level = tonumber(v.lvl),
                    icon = tonumber(v.avatar),
                    iconBg = 0,
                    roleId = v.id,
                    roleName = v.name,
                }
            end
        end
    end

    if self:IsExclusiveMode() then
        myServerList = nil
    end
    if myServerList then
        local newTbl = {}
        for k, v in ipairs(myServerList) do
            if v.id and self:IsServerValidShow(v) then
                local mergeId = tonumber(v.mergeToSvr) or 0
                local vid = v.id
                local playerInfo = playerInfoList[vid] or playerInfoList[mergeId]
                v.playerLevel = playerInfo and playerInfo.level or 0
                table.insert(newTbl, v)
            end
        end
        table.sort(newTbl, function(sA, sB)
            if sA.playerLevel ~= sB.playerLevel then
                return sA.playerLevel > sB.playerLevel
            end
            if sA.gsGroupDesc == sB.gsGroupDesc then
                return sA.orders > sB.orders
            end
            return sA.gsGroupDesc > sB.gsGroupDesc
        end)
        myServerList = newTbl
    end
    self._myPlayerServerList = myServerList or {}
end

