		gLxTKData:StepSdkLoginEvent()
	end

	if not self:CheckLoginDataValid() then
		self:CheckLoginBack()
	end
end
------------------------------------------------------------------
--- 从中心服获取账号
------------------------------------------------------------------

function LGameLogin:Step_AuthPlatform()
	local userId = self:GetSdkAccount() or ""
	local timestamp = gLSdkImpl:CallMethod(LSdkMethod.GetSdkTimeStamp) or ""
	local sign = gLSdkImpl:CallMethod(LSdkMethod.GetSdkSign) or ""

	self._loginSdkAccount = userId
	self._loginSdkTimestamp = timestamp
	self._loginSdkSign = sign
	self._isNeedRecordLogin = true
	self:SetGameStep(LStepLoginConst.STEP_PLATFORM_AUTH)

	local mathStr = string.match(userId, _USER_ID_PATTERN)
	if mathStr then
		self:SetLoginIdentityId(userId)
		self:OnAuthPlatformOk()
		FireEvent(EventNames.AUTH_PLATFORM_OK)
		return
	end

	local authUrl = self:GetAuthUrl()
	local channelId = self:GetChannelId() or 0
	local platformKey = self:GetPlatformKey() or ""
	local platformId = self:GetPlatformId() or 0
	local serverId = self:GetServerId() or ""
	local mergeToSvr = self:GetMergeToSvr() or 0
	local isRealName = gLSdkImpl:CallMethod(LSdkMethod.IsReadName) and 1 or 0
	local guid = gLSdkImpl:CallMethod(LSdkMethod.GetSdkGuid) or ""
	local cp_ext = gLSdkImpl:CallMethod(LSdkMethod.GetSdkCpExt) or "{}"
	local kkkChannelId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkDeployId) or 0
	local fromId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or 0

	--"channelId=v&cp_ext=v&fromId=v&guid=v&isRealName=v&kkkChannelId=v&platformId=v&platformKey=v&serverId=v&sign=v&timestamp=v&userId=v+clientKey"
	local tokenList = {
		"channelId="..channelId,
		"cp_ext="..cp_ext,
		"fromId="..fromId,
		"guid="..guid,
		"isRealName="..isRealName,
		"kkkChannelId="..kkkChannelId,
		"platformId="..platformId,
		"platformKey="..platformKey,
		"serverId="..serverId,
		"sign="..sign,
		"timestamp="..timestamp,
		"userId="..userId,
	}
	local suffix = table.concat(tokenList,"&")
	local gameToken = suffix..LGameLogin.AuthKey
	gameToken = CS.md5FromString(gameToken)

	--编码
	tokenList[2] = "cp_ext="..string.urlencode(cp_ext)
	local suffixUrlencode = table.concat(tokenList,"&")

	local uuid = LPlayerPrefs.uuidFirstBoot or ""
	local urlSuffix = "?"..suffixUrlencode.."&gameToken="..gameToken.."&mergeToSvr="..mergeToSvr.."&uuid="..uuid
	local urlList = {authUrl}

	urlSuffix = LUtil.MakeB64SendData(urlSuffix)
	LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function (...)
		GF.StopWait()
		--中途换账号了，或者重启了，不进下一步了
		if not self._isDestroy then
			if userId == self._loginSdkAccount and timestamp ==  self._loginSdkTimestamp and sign == self._loginSdkSign then
				self:OnAuthPlatform(...)
			end
		end
	end)
	
	-- 10秒后重新尝试
	GF.StartWait(10, nil, function()
		GF.StopWait()
		--中途换账号了，或者重启了，不进下一步了
		if not self._isDestroy then
			if userId == self._loginSdkAccount and timestamp ==  self._loginSdkTimestamp and sign == self._loginSdkSign then
				self:OnAuthPlatform(CS.YXWebRet.Timeout, "timeout", authUrl)
			end
		end
	end, true)
end

function LGameLogin:OnAuthPlatform(ret, result, url)
	if (ret ~= CS.YXWebRet.ok) then
		LogError(tostring(ret) .. " | " .. tostring(result))
		GF.OpenWnd("UIOrdinTip",{refId=40017,
			leftFunc=function() self:Step_BackLogin() end,
			func=function() self:Step_AuthPlatform() end
		})
		
		return
	end

	LXFW.LxLog.WEB(result)

	local resultTbl = JSON.decode(result)
	if(not resultTbl) then
		LogError("decode auth json data error ... ")
		GF.OpenWnd("UIOrdinTip",{refId=40017, 
			leftFunc=function() RestartGame() end,
			func=function() self:Step_AuthPlatform() end
		})
		return
	end

	local code = resultTbl.code
	if code ~= 0 then
		if code == 5 then
			local nowtime = tonumber(resultTbl.msg) or nil
			if self._gameServerData then
				self._gameServerData.timestamp = nowtime
			end
			self:Step_BackLogin()
			return
		end
		LogError("auth platform error ... code="..tostring(code))
		if code == 3 then
			GF.ShowMessage(ccClientText(136))
			self:Step_BackLogin()
			return
		end
		if code == 4 then
			GF.ShowMessage(ccClientText(142))
			self:Step_BackLogin()
			return
		end
		GF.OpenWnd("UIOrdinTip",{refId=40017, 
			leftFunc=function() RestartGame() end,
			func=function() self:Step_AuthPlatform() end
		})
		--GF.ShowMessage("auth platform error ... "..tostring(code))
		return
	end

	local identityId = resultTbl.identityId
	self:SetLoginIdentityId(identityId)
	self._loginSign = resultTbl.sign
	self._loginTimestamp = resultTbl.tstamp
	self._loginBirthDay = resultTbl.birthday
	self._loginIdentityName = resultTbl.identityName
	self._loginRealName = resultTbl.isRealName

	self:OnAuthPlatformOk()
	FireEvent(EventNames.AUTH_PLATFORM_OK)
end

function LGameLogin:OnAuthPlatformOk()
	local curServer = self._loginServerData
	self:Step_ConnectGameServer(curServer.ip,curServer.port)
end

