function LGameLogin:Step_ConnectGameServer(serverIp,serverPort)
	if not self:SetGameStep(LStepLoginConst.STEP_GAME_SERVER_CONNECT) then return end

	self._startConnect = true
	printInfoN(string.format("connect serverip=%s ,port=%s",tostring(serverIp),tostring(serverPort)))
	MgrCenter.NetworkMgr:Recreate()
    MgrCenter.NetworkMgr:SetConnectPara(serverIp,serverPort)
    MgrCenter.NetworkMgr:SetAccount(self:GetLoginIdentityId())
    MgrCenter.NetworkMgr:Connect()
end

function LGameLogin:IsStartConnect()
	return self._startConnect 
end

-----------------------------------------------------------------
--- 验证服务器
-----------------------------------------------------------------
function LGameLogin:Step_AuthServer()
	if not self:SetGameStep(LStepLoginConst.STEP_GAME_SERVER_AUTH) then return end
	self:StopGameTickTimer()

	local pb = LProtoHelper.CreateProto(LProtoIds.AuthReq)
	pb.identityId = self:GetLoginIdentityId()
	pb.timeStamp = self._loginTimestamp and self._loginTimestamp or tostring(int64.new(0,0))
	pb.sign = self._loginSign or ""
	pb.imei = LNativeHelper.GetImei() or ""
	pb.platformId = self:GetPlatformId() or 0
	pb.platformName = self:GetPlatformName() or ""

	pb.channelId = self:GetChannelId() or 0
	pb.channelKey = self:GetChannelKey() or ""
	pb.userId = self:GetSdkAccount() or ""
	pb.deviceType = LPlatformUtil.GetDeviceType()
	pb.mac = LNativeHelper.GetMacAddress() or ""
	pb.networkType = LPlatformUtil.GetNetworkType()
	pb.deviceName = USystemInfo.deviceModel or ""
	pb.serverName = self:GetServerName() or ""
	pb.isRealName = (tonumber(self._loginRealName) or 0 ) > 0
	pb.birthday = self._loginBirthDay or ""
	pb.uuid = LPlayerPrefs.uuidFirstBoot or ""
	pb.deviceCP = gLGameMemory:GetDeviceCp()
	pb.dbVersion = false
	-- 改成安装包的资源版本号 
	pb.appVer = gLxServerList.builtinAppVersion
	pb.appResVer = gLxServerList.activePackageVersion
	pb.osVer = USystemInfo.operatingSystem
	local devicWidth,devicHeight = LPlatformUtil.GetDeviceWH()
	pb.devPX = devicWidth..","..devicHeight
	pb.devCPU = gLGameMemory:GetCpuInfo()
	pb.devRAM = tostring(gLGameMemory:GetMemorySize())

	pb.channelName  = self:GetChannelName() or ""
	pb.platformKey  = self:GetPlatformKey() or ""
	pb.gpu  = gLGameMemory:GetGpuInfo()

	--pb.adid  = ""
	--pb.udid  = ""
	pb.realIp = self:GetRealIp() or ""
	pb.additional = gLSdkImpl:CallMethod(LSdkMethod.GetDeviceProperties) or gLSdkImpl:CallMethod(LSdkMethod.GetSdkAdditional) or ""

	local reconnectCnt = 0
	if MgrCenter.NetworkMgr then
		reconnectCnt = MgrCenter.NetworkMgr:GetReconnectCnt()
		if reconnectCnt == 0 and MgrCenter.NetworkMgr:IsReconnected() then
			reconnectCnt = 1
		end
	end
	pb.connectType = reconnectCnt > 0 and 1 or 0

	self._loginStep = 0

	SendMessage(pb,LProtoIds.AuthReq)
end

