	local l, h = int64.tonum2(int64Id)

	local account = pb.identityId

	self._playerName = pb.name

	--if(self._testCartoon) then
	--	--print("测试，开始开场动画")
	--	self._bNewPlayer = true
    --
	--end

	--------playerid 为0 需要创建角色
	if l <=0 and h <=0 then
		self:SetPlayCartoon()
		self:Step_CreatePlayerReq()--创建角色
		--print("没有角色，开始开场动画")
