function LGameLogin:Step_CreatePlayerReq()
	if not self:SetGameStep(LStepLoginConst.STEP_SERVER_PLAYER_CREATE) then return end

	local pb = LProtoHelper.CreateProto(LProtoIds.CreatePlayerReq)
	pb.identityId = self:GetLoginIdentityId()
	pb.imei = LNativeHelper.GetImei()
	pb.mac = LNativeHelper.GetMacAddress()
	pb.platformId1 = self:GetPlatformId() or 0
	pb.platformId2 = 0
	pb.channelId = self:GetChannelId() or 0
	pb.deviceType = LPlatformUtil.GetDeviceType()
	pb.network = LPlatformUtil.GetNetworkType()
	pb.language = gLGameLanguage:GetLanguageFlag()
	--USystemInfo.deviceUniqueIdentifier

	local deviceType = 2
	if CS.IsOSAndroid() then
		deviceType = 3
	elseif CS.IsOSIos() then
		deviceType = 4
	end
	pb.deviceType = deviceType

	local network = 0
	if CS.IsNetworkValid() then
		network = 1
		if LPlatformUtil.IsWifiValid() then
			network = 1
		elseif CS.IsCarrierDataValid() then
			network = 4
		end
	end
	pb.network = network

	pb.guid = gLSdkImpl:CallMethod(LSdkMethod.GetSdkGuid) or ""
	pb.kkkChannelId = tonumber(gLSdkImpl:CallMethod(LSdkMethod.GetSdkDeployId)) or 0
	pb.kkkFromId = tonumber(gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId)) or 0

    local invitationPlayerId = gLSdkImpl:CallMethod(LSdkMethod.GetInvitationPlayerId)
    --invitationPlayerId = "34093929630"
    if not string.isempty(invitationPlayerId) then
        pb.invitationPlayerId = invitationPlayerId
    end

	SendMessage(pb,LProtoIds.CreatePlayerReq)
end

function LGameLogin:OnCreatePlayerResp(pb,ret)
	self._playerId = tostring(pb.playerId)
	self._playerName = pb.name or ""
	self._bWaitNotifyPlayerCreate = true
	self:Step_LoginAccountOk()
end


