function LGameLogin:OnAuthNetError(msgId)
	if msgId == LProtoIds.AuthResp then
		self:StopDelayBackTimer()
		self._delayBackTimer = LxTimer.DelayTimeCall(function()
			self:Step_BackLogin()
		end, 1)
	end
end

function LGameLogin:OnAuthResp(pb,ret)
	if ret ~= 0 then
		LogError("auth error")
		GF.OpenWnd("UIOrdinTip",{refId=40015, para={"-1"},
			leftFunc=function() self:Step_BackLogin() end,
			func=function() RestartGame() end
		})
		return
	end
	local result = pb.result --/** 验证结果标识: 0:验证成功 1:md5校验失败 2:时戳过期  3:参数错误 */
	if result ~= 0 then
		LogError("auth error, resutl = "..tostring(result))
		GF.OpenWnd("UIOrdinTip",{refId=40015, para={tostring(result)},
			leftFunc=function() self:Step_BackLogin() end,
			func=function() RestartGame() end
		})
		return
	end
	--

    if self:CheckResVersionFormServer(pb.version, true) then
		gLGameLogin:Step_GetServerTime() 
	else
		MgrCenter.NetworkMgr:StopConnect("server ver not accept")
		LogError("server ver="..pb.version..", resVer="..gLxServerList.activePackageVersion)
		GF.OpenWnd("UIOrdinTip",{refId=40016, func=function() RestartGame() end})
	end 
end

function LGameLogin:CheckResVersionFormServer(serverResVersion, isFromAuth)
    if LGameSettings.resMode == 0 then
        --模拟器模式不在登录时候校验版本
        return true
    end
    local appVersion,packageVersion  = LxResUtil.GetActiveVersions()
    local resVersion = LxResUtil.ConvertToVersion(serverResVersion)
    if resVersion:CompareTo(packageVersion, isFromAuth) > 0 then
        LogError(string.format("server ver=%s, local ver=%s", tostring(resVersion), tostring(packageVersion)))
        return false
    end
    return true
end

function LGameLogin:OnServerTimeResp(pb,ret)
    local serverTime = pb.serverTime
    MgrCenter.NetworkMgr:SetServerTime(tostring(serverTime))
    self:SetServerTime(tonumber(serverTime), pb.rawOffset)

	self._loginStep = self._loginStep + 1
	if self._loginStep == 2 then
		gLGameLogin:Step_GetPlayerReq()
	end
end

function LGameLogin:OnAwaitLoginResp(pb)
	local fun = function()
		self:StopAwaitLoginTimer()
		self:Step_BackLogin()
	end
	MgrCenter.NetworkMgr:StopConnect("server awaitLogin resp")
	local nowTime = os.time()
	local time = math.floor((tonumber(pb.awaitEndTime) or 0 ) / 1000 - nowTime)
	if time < 3 then time = 3 end
	GF.OpenWnd("UIOrdinTip", {refId = 40020, para={time}, leftFunc = fun, closeFunc = fun, isCountDownPara= true})
	self._awaitLoginTickTimer = LxTimer.DelayTimeCall(function()
		self:StopAwaitLoginTimer()
		MgrCenter.NetworkMgr:Recreate()
		GF.CloseWndByName("UIOrdinTip")
		MgrCenter.NetworkMgr:CheckAlive()
	end, time)
end

function LGameLogin:OnResVersionResp(pb)
	--[[ 根据test/default包返回需求版本号
	/** 资源版本号 */
	optional int32 resVerion            = 1;
	/** 1为强制对比 0为不强制 */
	optional int32 resVerionCompearType = 2;
	]]

	local funNoticeResVerion = nil
	local funDelayNoticeResVerion = nil
	
	funNoticeResVerion =  function()
		GF.OpenWndDebug("UISistemTip",{refId=40010, leftFunc = function() funDelayNoticeResVerion() end, func=function() MgrCenter.NetworkMgr:StopConnect("res update quit"); RestartGame(); end})
	end
	funDelayNoticeResVerion =  function()
		self:StopDelayNoticeTimer()
		self._delayNoticeTimer = LxTimer.DelayTimeCall(function()
			self._delayNoticeTimer = nil
			funNoticeResVerion()
		end, 1800)
	end
	

	local reqResVerion = pb.resVerion
	local curResVerion = gLxServerList.activePackageVersion
	local bMustUpdate = pb.resVerionCompearType == 1

    if self:CheckResVersionFormServer(reqResVerion) then
		self._loginStep = self._loginStep + 1
		if self._loginStep == 2 then
			gLGameLogin:Step_GetPlayerReq()
		end 		
	else 
		if bMustUpdate or self._loginStep < 2 then
			MgrCenter.NetworkMgr:StopConnect("res update quit")
			GF.OpenWndDebug("UISistemTip",{refId=40011, func=function() RestartGame() end})
		else
			funNoticeResVerion()
		end
	end
end

function LGameLogin:OnQuitResp(pb)
	-- type /** 踢出类型,1-服务器维护,2-顶号,3-长时间未操作,4-后台踢下线 */
	local _showNoticeFunc = function()
		if gLGameLogin:HasNotice() then
			local dataList = gLGameLogin:GetPlatformNotices()
			GF.OpenWndTop("UIBulin",{type = 2,list = dataList, closeWndCallBack = function() RestartGame() end})
		else
			RestartGame()
		end
	end
	local quitType = pb.type or 0
	local isQuit = quitType > 0
	
	if quitType == 1 then
		GF.OpenWndDebug("UISistemTip",{refId=40012, leftFunc=function() self:Step_QueryServerListFromWeb(_showNoticeFunc, self:GetServerId()) end, func=function() RestartGame() end})
	elseif quitType == 2 then
		GF.OpenWndDebug("UISistemTip",{refId=40007, func=function() ReLoginGame() end})
	elseif quitType == 3 then
		GF.OpenWndDebug("UISistemTip",{refId=40018, leftFunc=function() RestartGame() end, func=function() MgrCenter.NetworkMgr:RecreateAndConnect() end})
	elseif quitType == 4 then
		GF.OpenWndDebug("UISistemTip",{refId=40005, func=function() RestartGame() end})
	end
	
	if isQuit then
		self._startConnect = false
		GF.StopWait()
		MgrCenter.NetworkMgr:StopConnect("system quit resp. type="..quitType)
	end
end

function LGameLogin:OnDisabledResp(pb)
	--[[
	/** 封禁类型,1-正常封禁 */
	optional int32 disableType      = 1;
	/** 封禁开始时间 */
	optional int32 disableBeginTime = 2;
	/** 封禁结束时间,-1表示永久 */
	optional int32 disableEndTime   = 3;
	/** 禁言开始时间*/
	optional int32 silentBeginTime  = 4;
	/** 禁言结束时间.-1表示永久 */
	optional int32 silentEndTime    = 5;
	]]
	
	self._isChatSilent = false
	
	local disable = pb.disableType or 0
	local disableBeginTime = tonumber(pb.disableBeginTime) or 0
	local disableEndTime = tonumber(pb.disableEndTime) or 0
	local silentBeginTime = tonumber(pb.silentBeginTime) or 0
	local silentEndTime = tonumber(pb.silentEndTime) or 0
	local curTime = tonumber(GetTimestamp())
	local delayDisableTime = 0
	local isQuit = false
	local isSilent = false

	local tipsParas = nil
	if disable > 0 then
		-- 封号
		if disableBeginTime == -1 then
			delayDisableTime = 0
		else
			delayDisableTime = disableBeginTime - curTime
		end
		
		if disableEndTime == -1 then
			isQuit = true
			local id = (disable == 1) and 40003 or 40013
			tipsParas = {refId=id, func=function() RestartGame() end}
		elseif disableEndTime > curTime then
			isQuit = true

			--local timeStr = LUtil.FormatTimeStr(disableEndTime * 1000)
			local timeStr = os.date("%Y/%m/%d %H:%M:%S", disableEndTime)

			local id = (disable == 1) and 40004 or 40014
			tipsParas = {refId=id, para={timeStr},func=function() RestartGame() end}
		end
	end
	
	-- 禁言
	self._chatSilentEndTime = silentBeginTime
	self._chatSilentBeginTime = silentEndTime
	
	if silentBeginTime == -1 then
		delayDisableTime = 0
	else
		delayDisableTime = silentBeginTime - curTime
	end
	self._chatSilentEndTime = silentEndTime
	if silentEndTime == -1 then 		
		isSilent = true
		tipsParas = {refId=130000, func=function()  end}
	elseif silentEndTime > curTime then
		isSilent = true
		local timeStr = LUtil.FormatTimeStr(silentEndTime * 1000)
		tipsParas = {refId=130001, para={timeStr},func=function()  end}
	end
	
	if tipsParas then
		if delayDisableTime > 0 then
			self:StopDelayDisableTimer()
			self._delayDisableTimer = LxTimer.DelayTimeCall(function()
				self._delayDisableTimer = nil
				self._isChatSilent = isSilent
				GF.OpenWndDebug("UISistemTip", tipsParas)
			end, delayDisableTime)
		else
			self._isChatSilent = isSilent
			GF.OpenWndDebug("UISistemTip", tipsParas)
		end 
	end
	
	if isQuit then
		self._startConnect = false
		MgrCenter.NetworkMgr:StopConnect("disabled resp")
	end
end

function LGameLogin:Step_BackLogin()
	if self._delayBackTimer then LxTimer.DelayTimeStop(self._delayBackTimer) end
	self._delayBackTimer = nil

	if GF.IsInMainScene() then
		ReLoginGame()
		return
	end
	local gameStep = self._gameStep
	if gameStep >= LStepLoginConst.STEP_SERVER_MODEL_DATA then
		if gLModelManager then gLModelManager:ClearAllModels() end
	end
	if gameStep >= LStepLoginConst.STEP_GAME_SERVER_CONNECT then
		MgrCenter.NetworkMgr:Recreate()
	end
	self:ClearLoginStatus()
	FireEvent(EventNames.LOGIN_BACK_LOGIN)
end

function LGameLogin:Step_LoginAccountOk()
    if LGameSettings.isSubpackage and not LGameData.isHasDownLuaAbSubpackage then
        ---未完成luaab 分包预下载，先完成
        CS.CallCsFun(CsFunType.Down, { CsDownType.DownLuaAbSubpackage }, function()
            self:OnDownloadLuaAbSubpackageComplete()
            self:OnLoginAccountOk()
        end)
    else
        self:OnLoginAccountOk()
    end
end

function LGameLogin:OnLoginAccountOk()
    if not self:SetGameStep(LStepLoginConst.STEP_SERVER_PLAYER_INFO) then return end

    self:ReqPlayerInfo()
end

--请求玩家基本信息
function LGameLogin:ReqPlayerInfo()
	local pb = LProtoHelper.CreateProto(LProtoIds.PlayerDataReq)
	SendMessage(pb,LProtoIds.PlayerDataReq)
end

function LGameLogin:RespPlayerInfo(pb)
	local notifyPlayerCreate = self._bWaitNotifyPlayerCreate
	self._bWaitNotifyPlayerCreate = nil

	if not self:SetGameStep(LStepLoginConst.STEP_SERVER_MODEL_DATA) then return end

	self._playerData = LProtoHelper.ProtoToPureTable(pb.data)
	local playerLevel = tonumber(self._playerData.level)
    self._isInitOpenSex = true
	self:CheckOpenSex(playerLevel)

	---- 大于5级的玩家点开始游戏后重启并下载所有资源
	--if playerLevel >= 5  then

	--	MgrCenter.NetworkMgr:StopConnect("res need update full")
	--	GF.OpenWndDebug("UISistemTip",{refId=40021, func=function() RestartGame() end})
	--	return
	--end

	if notifyPlayerCreate then
		gLSdkImpl:CallMethod(LSdkMethod.OnPlayerCreate)
		local isForeign = LGameSettings.platformRegion ~= LRegionConst.CHINA
		if isForeign then
			if gLxTKData then gLxTKData:OnLanguageTAReq() end
		end
	end
	local mainCitySkin = self._playerData.mainCitySkin or 0

	if mainCitySkin ~= 0 then
		local ref = GameTable.CastleSkinRef[mainCitySkin]
		if ref then
			gLGameDisplayTheme:SetMapTheme(ref.prefab)
		end
	else
		--自动设置策划配置限时主城皮肤
		-- gModelPlayerSpace:SetAutoUseDefaultCityMapTheme()
	end

	FireEvent(EventNames.LOGIN_ACCOUNT_OK)
end
