function LGameLogin:OnLoginModelOk()
	-- 发送登录完成请求
	self:Step_LoginReq()
end

-----------------------------------------------------------------
---登陆完成请求服务器推送
function LGameLogin:Step_LoginReq()
	if not self:SetGameStep(LStepLoginConst.STEP_LOGIN_OK_SEND) then return end

    self:OnLoginReq()
end

function LGameLogin:OnLoginReq(bNavigate)
    local pb = LProtoHelper.CreateProto(LProtoIds.LoginReq)
    pb.playerId = self:GetPlayerId() or "0"
    pb.realGender = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.GetSdkSex) or -1
    pb.realAge = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.GetSdkUserAge) or 0
    SendMessage(pb,LProtoIds.LoginReq)
end

function LGameLogin:OnLoginResp(pb)
	if not self:SetGameStep(LStepLoginConst.STEP_LOGIN_FINISH) then return end

	local isInMainScene = GF.IsInMainScene()

	LogWarn("LGameLogin:OnLoginResp Login OK!")
	if MgrCenter.NetworkMgr:IsReconnected() then
        MgrCenter.NetworkMgr:ShowNetBlock(false)
		MgrCenter.NetworkMgr:ResendLostMessages()
		FireEvent(EventNames.NET_RECONNECTED)
	end

    MgrCenter.NetworkMgr:EnableResend()

	--if gModelPlayer and not gModelPlayer:IsNoName() then
	--TODO
	if gModelPlayer then
		if self._isNeedRecordLogin then
			self._isNeedRecordLogin = false
			gLSdkImpl:CallMethod(LSdkMethod.OnPlayerLogin)
		end
	end

	gLSdkImpl:CallMethod(LSdkMethod.DoSdkSwitchFinish)

	--local pushDeviceId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPushDeviceId)
	local pushDeviceId = gLSdkImpl:CallMethod(LSdkMethod.GetFcmToken)
	if not string.isempty(pushDeviceId) then
		local pb = LProtoHelper.CreateProto(LProtoIds.DelayDataReq)
		pb.pushDeviceId = pushDeviceId
		pb.realGender = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.GetSdkSex) or -1
		pb.realAge = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.GetSdkUserAge) or 0
		SendMessage(pb,LProtoIds.DelayDataReq)
	end

	---发送货币符号
	gModelPlayerSpace:OnPlayerChangeInfoReq(4, gLSdkImpl:CallMethod(LSdkMethod.GetCurrency))

	if not GF.IsInMainScene() then

        local loadEndFunc = function()
            if gModelBlockMiniGame:CheckNeedLoginEntranceGame() then
            --if(true)then
                local refId = gModelBlockMiniGame:GetWXBSFirstRefId()
                if(refId)then
                    gModelBlockMiniGame:SetWXBSFlag(true)
                    GF.ChangeMap("LBlockMiniGameMap", nil, {refId = refId })
                end
            end
        end
        if gModelBlockMiniGame:CheckNeedLoginEntranceGame() then
        --if(true)then
            gModelBlockMiniGame:SetWXBSFlag(true)
        end
        GF.ChangeToMainScene({ waitBlack = true, clearBgWnd = true, loadEndFunc = loadEndFunc})
		--GF.ChangeToMainScene({waitBlack=true, clearBgWnd=true})
	else
		self:StartGameTickTimer()
	end
	FireEvent(EventNames.On_Hero_Change)
    FireEvent(EventNames.ON_CHARGE_MONEY_SET)
end

function LGameLogin:OnDelayDataResp(pb)

end

