function LGameLogin:GetLoginFigure()
	local autoUse = LPlayerPrefs.autoUseLoginRole == "1"
	if autoUse then
		local loginRole = GameTable.OneNightConfigRef["loginRole"]

		--优先判断包id，根据包id显示不同的登录背景图
		local packLoginRole = GameTable.OneNightConfigRef["packLoginRole"]
		if not string.isempty(packLoginRole) then
			local package_id = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.GetInitPackageId) or "0"
			local packLoginRoleList = string.split(packLoginRole, "|")
			for k,v in ipairs(packLoginRoleList) do
				local packLoginData = string.split(v, '=')
				local packId = packLoginData[1]
				if packId == package_id then
					loginRole = tonumber(packLoginData[2])
					break
				end
			end
		end

		local record = tonumber(LPlayerPrefs.loginRoleRecord)
		if loginRole and loginRole > 0 and record ~= loginRole then
			return loginRole
		end
	end

	local refId = LPlayerPrefs.loginFigure
	if string.isempty(refId) then
		return
	end

	return tonumber(refId)
end

