function LGameLogin:CheckOpenSex(lv)
	if not gLGameTable then return end
    if not self._isInitOpenSex then return end

    local isCtrlAb, isBTest
    if gLSdkImpl then
        isCtrlAb, isBTest = gLSdkImpl:CallMethod(LSdkMethod.GetABTestRes)
    end
    if isCtrlAb then
        gLGameTable:SetSensitive(isBTest)
    elseif self:IsOpenSex() and lv < self._sexLvl then
		gLGameTable:SetSensitive(true)
	else
		gLGameTable:SetSensitive(false)
	end

	if gLGameTable:IsNeedUpdateSensitive() then
		gLGameTable:ClearNeedUpdateSensitive()

		gLGameTable:ClearSensitiveCache()
		if gLxTKData then
			gLxTKData:ParseTKStepDatas()
		end

        if self:IsOpenSex() then
		    self:OnSkinShieldReq(gLGameTable:IsSensitive())
        end

		FireEvent(EventNames.ON_SHIELD_UPDATE)
	end
end

function LGameLogin:OnSkinShieldReq(shield)
	local pb = LProtoHelper.CreateProto(LProtoIds.SkinShieldReq)
	pb.shield = shield
	SendMessage(pb, LProtoIds.SkinShieldReq)
end

------------------------------------------------------------------
--- 开服前预抽卡数据获取
------------------------------------------------------------------
function LGameLogin:PreselectHeroRequestURL(justGetData, heroId)
	if not self:IsOpenPreDrawCard() then
		return
	end

	local sdkUserId = self:GetSdkAccount() or 0
	if gModelCallHero:CheckHasGetPrepareMirrorCallSdk(sdkUserId) then
		return
	end

	if not heroId then
		heroId = 0
	end

	local curTime = self:GetTimeStamp() + GetTimestamp()
	local reqType = justGetData and 0 or 1 --1= 上传英雄， 0=查询

	local sign = CS.md5FromString(sdkUserId..heroId..curTime..LGameLogin.AuthKey)

	local tokenList = {
		"uid="..sdkUserId,
		"hid="..heroId,
		"time="..curTime,
		"type="..reqType,
		"sign="..sign,
	}

	local suffix = table.concat(tokenList,"&")

	local urlList = self:GetServicesUrlList()

	local urlSuffix = "api/preselectHero.do?"..suffix
	urlSuffix = LUtil.MakeB64SendData(urlSuffix)

	LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function (ret, result, url)
		if ret ~= 0 then return end

		LXFW.LxLog.WEB(result)
		local resultTbl = JSON.decode(result)
		if not resultTbl then return end

		local code = resultTbl.code
		if code ~= 0 then
			if code == 2 then
				printErrorN2("预抽卡平台请求", resultTbl.msg)
				gModelCallHero:AutoClearLocalPrepareMirrorCallData(sdkUserId)
				if self._isAutoLockPrepareCallHero then
					self._isAutoLockPrepareCallHero = false
					gModelCallHero:AutoLockPrepareMirrorCallHero()
				end
				return
			else
				printErrorN2("预抽卡平台请求错误", resultTbl.msg)
				return
			end
		end

        if reqType == 0 then
            local selectHeroId = tonumber(resultTbl.hid)
            local getState = tonumber(resultTbl.state)
			gModelCallHero:AutoClearLocalPrepareMirrorCallData(sdkUserId)
            gModelCallHero:SetPrepareMirrorCallData(selectHeroId, getState)
			if getState == 1 then
				gModelCallHero:SetLockPrepareMirrorCallSdk(sdkUserId)
			end

			if self._isAutoLockPrepareCallHero then
				self._isAutoLockPrepareCallHero = false
				gModelCallHero:AutoLockPrepareMirrorCallHero()
			end
			FireEvent(EventNames.ON_PREPARE_SERVER_READY)
        else
            self:PreselectHeroRequestURL(true)
			self:PreselectHeroTagHandlerURL(heroId)
        end
	end)
end
--预抽卡数数打点
function LGameLogin:PreselectHeroTagHandlerURL(heroId)
	if not heroId then return end

	local tokenList = {
		"hero_refid="..heroId,												--取玩家锁定的，伙伴ID
		--"summon_hero_list="..curTime,										--玩家可选的伙伴的列表
		"remain_amount="..gModelCallHero:GetLocalPrepareMirrorHaveCallNum(),--玩家当前剩余抽卡次数
		"dev_type="..tostring(LPlatformUtil.GetDeviceName()),				--设备唯一ID
		"dev_uuid="..string.urlencode(LPlayerPrefs.uuidFirstBoot or ""), --设备硬件类别（pc/浏览器/ios）
		"dev_version="..string.urlencode(USystemInfo.operatingSystem),		--设备操作系统版本
		"sdk_account_id="..(self:GetSdkAccount() or ""),					--SDK账号ID（渠道给的那个）
		"res_version="..string.urlencode(gLxServerList.activePackageVersion),		--应用当前的资源版本号
		"app_version="..string.urlencode(gLxServerList.builtinPackageVersion),	--应用打包时的资源版本号
		"channel_mapping_id="..(gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or "0"),--安装包ID
		"package_mapping_id="..(self:GetChannelId() or "0"),--渠道ID
	}

	local suffix = table.concat(tokenList,"&")

	local urlList = self:GetServicesUrlList()

	local urlSuffix = "stat/heroPreselect4TgaHandler.do?"..suffix
	urlSuffix = LUtil.MakeB64SendData(urlSuffix)

	LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function (ret, result, url)
		LXFW.LxLog.WEB(result)
		printErrorN2("预抽卡打点，平台请求结果", result)
	end)
end

function LGameLogin:StopGameTickTimer()
	if self._gameTickTimer then
		LxTimer.DelayTimeStop(self._gameTickTimer)
		self._gameTickTimer = nil
	end
end

function LGameLogin:StartGameTickTimer()
	self:StopGameTickTimer()
	self._gameTickTimer = LxTimer.LoopTimeCall(function()
        MgrCenter.NetworkMgr:SendTick()
	end, 5,true)
end

function LGameLogin:OnAcrossDayResp(pb, ret)
    --设置服务器时间
    local serverTime = pb.time
    MgrCenter.NetworkMgr:SetServerTime(tostring(serverTime))
    self:SetServerTime(tonumber(serverTime), self._serverTimeZone or 0)

    FireEvent(EventNames.ON_TIME_ZERO)
end

function LGameLogin:OnTickResp(pb, ret)

end


function LGameLogin:SetServerTime(time, zone)
    self._serverTime = time
    self._serverTimeZone = zone
    self._serverTimeStart = Time.realtimeSinceStartup

    _G.S_SERVER_TIME = time * 0.001
    _G.S_TIME_ZONE = zone * 0.001
    _G.S_TIME_START = self._serverTimeStart
end

