function LGameLogin:TryDownloadLuaAbSubpackage()
    if not CS.IsWebGL() then
        CS.CallCsFun(CsFunType.HideLaunchScreen)
        return
    end
    --self:RequireProto()

    --if not LGameSettings.isNotBootBackground then
    --    CS.CallCsFun(CsFunType.HideLaunchScreen)
    --end

    --登录界面显示后这里提前加载lua代码分包
    CS.CallCsFun(CsFunType.Down, { CsDownType.DownLuaAbSubpackage }, function()
        self:OnDownloadLuaAbSubpackageComplete()
    end)
end

