end

function LGameLogin:OnDealSceneEnterFinished()
    if not (CS.IsWebGL() and LGameSettings.isSubpackage) then
        LogWarn("-->>> LLoginScene, CreateAllModels")
        gLModelManager:CreateAllModels()
    end
    LogWarn("-->>> LLoginScene, LOGIN_SCENE_FINISH_LOAD")
    FireEvent(EventNames.LOGIN_SCENE_FINISH_LOAD)
    LogWarn("-->>> LLoginScene, playMusic")
    self:PlayLoginMusic()

    self:StopDelayTimer()
    self:StartWaitOpenLogin()
end

function LGameLogin:OnDealScenePrepare()
    --准备icon缓存池子
    local resTag = CS.RES_TAG_PERSISTENT
    local cachePoolList = {
        { path = CS.ResPath(CS.RES_UI_WND,"ItemIconNew"), name ="ItemIconNew", resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"HeroIconNew"), name ="HeroIconNew",  resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"EquipIconNew"), name ="EquipIconNew", resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"RuneIconNew"), name ="RuneIconNew",  resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"OutfitIconNew"), name ="OutfitIconNew",  resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"EmptyItemIconNew"), name ="EmptyItemIconNew",  resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"GolemIconNew"), name ="GolemIconNew",  resTag = resTag },
        { path = CS.ResPath(CS.RES_UI_WND,"HalidomIconNew"), name ="HalidomIconNew",  resTag = resTag },
        --{ path = CS.ResPath(CS.RES_UI_WND,"EquipIconNew_RH"), name ="EquipIconNew_RH",  resTag = resTag },
        --{ path = CS.ResPath(CS.RES_UI_WND,"RuneIconNew_RH"), name ="RuneIconNew_RH",  resTag = resTag },
    }

    self._cachePoolMax = #cachePoolList
    if self._cachePooMax == 0 then
        self:OnScenePrepareOk()
        return
    end
    self._curPoolCnt = 0
    self._curPoolLoaded = 0
    self._cachePoolList = cachePoolList

    self:StartLoopIconPoolTimer()
end

function LGameLogin:OnDealSceneDestroy()
    if self._isDisposed then return end
    self:StopDelayTimer()
    self:StopLoopIconPoolTimer()
end


function LGameLogin:EnumCachePoolList()
    local idx = self._curPoolCnt
    if idx >= self._cachePoolMax then
        return
    end
    local frameCnt = 2
    local initSize = 10
    local max = self._cachePoolMax
    local bContinue = true
    for i=1,frameCnt do
        idx = idx + 1
        self._curPoolCnt = idx
        local data = self._cachePoolList[idx]
        GF.PrepareGamePool(LPoolTagConst.TAG_ICON_CACHE,LSimplePool.Static_MakeWndArgs(data.path, data.name, data.resTag),function ()
            self:OnPrepareGamePoolData()
        end, initSize)
        if idx >= max then
            bContinue = false
            break
        end
    end
end

function LGameLogin:OnPrepareGamePoolData()
    if self._isDestroy then return end
    self._curPoolLoaded = self._curPoolLoaded + 1
end

function LGameLogin:StopLoopIconPoolTimer()
    if self._loopIconPoolTimer then
        LxTimer.DelayTimeStop(self._loopIconPoolTimer)
        self._loopIconPoolTimer = nil
    end
end

function LGameLogin:StartLoopIconPoolTimer()
    self:StopLoopIconPoolTimer()
    self._loopIconPoolTimer = LxTimer.LoopTimeCall(function()
        self:EnumCachePoolList()
        if self._curPoolLoaded >= self._cachePoolMax then
            self:OnScenePrepareOk()
        end
    end, 0.033)
end

function LGameLogin:OnScenePrepareOk()
    self:StopLoopIconPoolTimer()
    --等待BootBackGround 界面完成 暂时用计时器
    self:StopDelayTimer()
    self._delayTimer = LxTimer.DelayTimeCall(function()
        self._delayTimer = nil

        local sceneFunc = self.sceneEnterFunc
        if sceneFunc then
            self.sceneEnterFunc = nil
            sceneFunc()
        end
    end, 0.03)
end

function LGameLogin:StartWaitOpenLogin()
    --等待loading 界面完成 暂时用计时器
    self:StopDelayTimer()
    self._delayTimer = LxTimer.DelayTimeCall(function()
        self._delayTimer = nil
        if LGameSettings.isLoginLoadFont then
            self:DealFont(function()
                self:OpenLogin()
            end)
        else
            self:OpenLogin()
        end
    end, 0.15)
end

