function LGameLogin:ChangeTmpFallbackFont(changeType, obj)
    CardEHT.ManagerCenter.GameMgr:ChangeTmpFallbackFont(changeType, obj)
end

function LGameLogin:onDownBackupFont(callback)
    --处理返回空字体的情况，加载备用字体
    --local fontPath = "Font/SysFont"
    local fontName = "zhcn/OPPOSansRMixBBackSDF"
    --gprint("onDownBackupFont", fontPath, fontName)
    local fontPath = "Font/SysFont/" .. fontName .. ".asset"
    local requester = LxResUtil.GetAssetRequester(fontPath, typeof(UnityEngine.Object), function(fontAsset)
        if fontAsset == nil then
            if LOG_ERROR_ENABLED then
                LogError("字体为空："..fontPath)
            end
            callback()
            return
        end
        self:ChangeTmpFallbackFont(1, fontAsset)
        self:OnTmpFontUpdate()
        callback()
    end)
    requester:StartRequester()
end

function LGameLogin:OnTmpFontUpdate()
    FireEvent(EventNames.TMP_FONT_UPDATE)
end

function LGameLogin:OpenLogin()
    GF.OpenWnd("UILon", { isInitGame = true })
end

function LGameLogin:StopDelayTimer()
    if self._delayTimer then
        LxTimer.DelayTimeStop(self._delayTimer)
        self._delayTimer = nil
    end
end

function LGameLogin:PlayLoginMusic()
    if toboolean(LPlayerPrefs.muteLoginMusic) then
        return
    end
    local ref = GameTable.SoundEffectSceneRef[self:GetClassName()]
    if ref and ref.soundName then
        if gLGameAudio then gLGameAudio:PlayMapMusic(ref.soundName) end
    end
end

function LGameLogin:SetSceneEnterCallBack(func)
    self.sceneEnterFunc = func
end

